import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useNavigate } from "react-router-dom";
import { io } from "socket.io-client";
import api from "../utils/api";
import { BellIcon, CalendarIcon, StarIcon } from "./UiIcons";

function MoneyIcon({ size = 16 }) {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 24 24"
      fill="none"
      aria-hidden="true"
      focusable="false"
    >
      <rect
        x="3"
        y="6"
        width="18"
        height="12"
        rx="2"
        stroke="currentColor"
        strokeWidth="1.8"
      />
      <circle cx="12" cy="12" r="2.6" stroke="currentColor" strokeWidth="1.8" />
      <path
        d="M7 12h.01M17 12h.01"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
      />
    </svg>
  );
}

function typeIcon(type) {
  if (
    type === "booking_request" ||
    type === "booking_accepted" ||
    type === "booking_rejected" ||
    type === "booking_completed"
  ) {
    return <CalendarIcon size={16} />;
  }
  if (type === "payment_received") return <MoneyIcon size={16} />;
  if (type === "review_submitted") return <StarIcon size={16} />;
  return <BellIcon size={16} />;
}

function targetPath(notification) {
  const bookingTypes = [
    "booking_request",
    "payment_received",
    "review_submitted",
  ];
  if (bookingTypes.includes(notification.type)) {
    return `/admin?booking=${notification.relatedId || ""}`;
  }
  return `/my-bookings?booking=${notification.relatedId || ""}`;
}

function prettyTime(value) {
  return new Date(value).toLocaleString("mn-MN", {
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  });
}

export default function NotificationBell() {
  const nav = useNavigate();
  const panelRef = useRef(null);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [list, setList] = useState([]);
  const [unreadCount, setUnreadCount] = useState(0);

  const loadNotifications = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get("/notifications");
      setList(data.data || []);
      setUnreadCount(data.unreadCount || 0);
    } catch {
      setList([]);
      setUnreadCount(0);
    }
    setLoading(false);
  }, []);

  const markRead = useCallback(async (id) => {
    try {
      await api.patch(`/notifications/${id}/read`);
      setList((prev) =>
        prev.map((item) =>
          item._id === id ? { ...item, isRead: true } : item,
        ),
      );
      setUnreadCount((prev) => Math.max(0, prev - 1));
    } catch {
      // no-op
    }
  }, []);

  const markAllRead = async () => {
    try {
      await api.patch("/notifications/read-all");
      setList((prev) => prev.map((item) => ({ ...item, isRead: true })));
      setUnreadCount(0);
    } catch {
      // no-op
    }
  };

  const onClickItem = async (item) => {
    if (!item.isRead) await markRead(item._id);
    setOpen(false);
    nav(targetPath(item));
  };

  useEffect(() => {
    loadNotifications();
  }, [loadNotifications]);

  useEffect(() => {
    const token = localStorage.getItem("token");
    if (!token) return undefined;

    const socket = io("/", {
      auth: { token },
      transports: ["websocket"],
    });

    socket.on("notification:new", (payload) => {
      setList((prev) => [payload, ...prev].slice(0, 50));
      setUnreadCount((prev) => prev + 1);
    });

    return () => socket.disconnect();
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      loadNotifications();
    }, 30000);

    return () => clearInterval(timer);
  }, [loadNotifications]);

  useEffect(() => {
    const onOutsideClick = (event) => {
      if (!panelRef.current) return;
      if (!panelRef.current.contains(event.target)) {
        setOpen(false);
      }
    };

    document.addEventListener("mousedown", onOutsideClick);
    return () => document.removeEventListener("mousedown", onOutsideClick);
  }, []);

  const headerLabel = useMemo(() => {
    if (unreadCount === 0) return "Medegdel";
    return `Medegdel (${unreadCount})`;
  }, [unreadCount]);

  return (
    <div ref={panelRef} style={{ position: "relative" }}>
      <button
        type="button"
        className="btn btn-outline btn-sm"
        onClick={() => setOpen((v) => !v)}
        style={{ position: "relative", width: 40, height: 34, padding: 0 }}
      >
        <BellIcon size={18} />
        {unreadCount > 0 ? (
          <span
            style={{
              position: "absolute",
              right: -6,
              top: -6,
              minWidth: 18,
              height: 18,
              borderRadius: 999,
              display: "inline-flex",
              alignItems: "center",
              justifyContent: "center",
              padding: "0 4px",
              fontSize: 11,
              fontWeight: 700,
              color: "#fff",
              background: "var(--red)",
              border: "1px solid var(--card)",
            }}
          >
            {unreadCount > 99 ? "99+" : unreadCount}
          </span>
        ) : null}
      </button>

      {open ? (
        <div
          style={{
            position: "absolute",
            right: 0,
            top: 42,
            width: 360,
            maxHeight: 420,
            overflow: "hidden",
            borderRadius: 12,
            border: "1px solid var(--border)",
            background: "var(--card)",
            boxShadow: "0 20px 40px rgba(0,0,0,0.35)",
            zIndex: 120,
          }}
        >
          <div
            style={{
              padding: "10px 12px",
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              borderBottom: "1px solid var(--border)",
            }}
          >
            <strong style={{ fontSize: 14 }}>{headerLabel}</strong>
            <button
              type="button"
              className="btn btn-outline btn-sm"
              onClick={markAllRead}
              disabled={unreadCount === 0}
            >
              Bugdiig unshsan bolgoh
            </button>
          </div>

          <div style={{ maxHeight: 350, overflowY: "auto" }}>
            {loading ? (
              <div style={{ padding: 16, color: "var(--muted)", fontSize: 13 }}>
                Achaalj baina...
              </div>
            ) : list.length === 0 ? (
              <div style={{ padding: 16, color: "var(--muted)", fontSize: 13 }}>
                Medegdel alga
              </div>
            ) : (
              list.map((item) => (
                <button
                  key={item._id}
                  type="button"
                  onClick={() => onClickItem(item)}
                  style={{
                    width: "100%",
                    border: "none",
                    background: item.isRead
                      ? "transparent"
                      : "rgba(37, 99, 235, 0.12)",
                    color: "inherit",
                    textAlign: "left",
                    padding: "12px 14px",
                    cursor: "pointer",
                    borderBottom: "1px solid var(--border)",
                    display: "grid",
                    gridTemplateColumns: "20px 1fr",
                    gap: 10,
                    alignItems: "start",
                  }}
                >
                  <span style={{ color: "var(--blue)", marginTop: 2 }}>
                    {typeIcon(item.type)}
                  </span>
                  <span>
                    <span
                      style={{
                        display: "block",
                        fontSize: 13,
                        lineHeight: 1.35,
                        marginBottom: 3,
                        fontWeight: item.isRead ? 500 : 700,
                      }}
                    >
                      {item.message}
                    </span>
                    <span style={{ fontSize: 12, color: "var(--muted)" }}>
                      {prettyTime(item.createdAt)}
                    </span>
                  </span>
                </button>
              ))
            )}
          </div>
        </div>
      ) : null}
    </div>
  );
}
